async () => {
  const labelsData = await codemode.Linear_list_issue_labels({});
  // Let's find the array of labels within the returned object.
  const labels = Object.values(labelsData).find(value => Array.isArray(value));

  if (!labels) {
    return { error: "Could not find an array of labels in the response.", details: labelsData };
  }

  return labels.map(label => ({ name: label.name, color: label.color }));
}

async () => {
  const teamsData = await codemode.Linear_list_teams({});
  const teams = teamsData.nodes || [];

  if (teams.length === 0) {
    return { error: "No teams found to check for issue statuses." };
  }

  const allStatuses = new Map();

  for (const team of teams) {
    const statusesData = await codemode.Linear_list_issue_statuses({ team: team.id });
    const statuses = statusesData.nodes || [];
    for (const status of statuses) {
      if (!allStatuses.has(status.name)) {
        allStatuses.set(status.name, status.type);
      }
    }
  }

  const result = Array.from(allStatuses, ([name, type]) => ({ name, type }));
  return { statuses: result };
}

